public class CyclicEncoder {

    public static String encodeCyclic(String s) {
        /*
         * returns encoded string by cycling groups of three characters.
         */
        // split string to groups. Each of length 3.
        StringBuilder encoded = new StringBuilder();
        for (int i = 0; i < s.length(); i += 3) {
            String group = s.substring(i, Math.min(i + 3, s.length()));
            // cycle elements in each group. Unless group has fewer elements than 3.
            if (group.length() == 3) {
                encoded.append(group.charAt(1)).append(group.charAt(2)).append(group.charAt(0));
            } else {
                encoded.append(group);
            }
        }
        return encoded.toString();
    }

